commit dd116369f646d023a2e7e5c145a1bed5dcf9a45c
Author: Nikita Popov <npopov@redhat.com>
Date:   Thu Nov 7 14:09:45 2024 +0100

    [InstSimplify] Fix incorrect poison propagation when folding phi (#96631)

    We can only replace phi(X, undef) with X, if X is known not to be
    poison. Otherwise, the result may be more poisonous on the undef branch.

    Fixes https://github.com/llvm/llvm-project/issues/68683.

diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 2cb2612bf611..daa468ac095c 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -5315,7 +5315,14 @@ static Value *simplifyPHINode(PHINode *PN, ArrayRef<Value *> IncomingValues,
     // If we have a PHI node like phi(X, undef, X), where X is defined by some
     // instruction, we cannot return X as the result of the PHI node unless it
     // dominates the PHI block.
-    return valueDominatesPHI(CommonValue, PN, Q.DT) ? CommonValue : nullptr;
+    if (!valueDominatesPHI(CommonValue, PN, Q.DT))
+      return nullptr;
+
+    // Make sure we do not replace an undef value with poison.
+    if (HasUndefInput &&
+        !isGuaranteedNotToBePoison(CommonValue, Q.AC, Q.CxtI, Q.DT))
+      return nullptr;
+    return CommonValue;
   }

   return CommonValue;


